def generate_sequence(length):
    sequence = []
    used_values = set()
    candidate = 1
    while len(sequence) < length:
        is_valid = True
        candidate_values = set()
        for element in sequence:
            s = candidate + element
            d = candidate - element
            p = candidate * element
            pairs = {s, d, p}
            if len(pairs) < 3 or not pairs.isdisjoint(used_values) or not pairs.isdisjoint(candidate_values):
                is_valid = False
                break
            candidate_values.update(pairs)
        if is_valid:
            sequence.append(candidate)
            used_values.update(candidate_values)
        candidate += 1
    return sequence

